-- Case 021: secure view with nested CTEs, lateral flatten, masking-aware columns, and comments
CREATE OR REPLACE SECURE VIEW MART.VW_CUSTOMER_SUPPORT_CONTEXT COPY GRANTS COMMENT = 'Secure support context view / セキュア問い合わせ文脈ビュー' AS WITH latest_profile AS(SELECT customer_id,tenant_id,region,email,display_name,profile,updated_at FROM CORE.PROTECTED_CUSTOMER_PROFILE QUALIFY ROW_NUMBER() OVER(PARTITION BY customer_id ORDER BY updated_at DESC NULLS LAST,created_at DESC) = 1),open_tickets AS(SELECT t.ticket_id,t.customer_id,t.tenant_id,t.created_at,t.status,t.severity,t.subject,c.value:category::STRING AS category,c.value:confidence::FLOAT AS category_confidence FROM CORE.SUPPORT_TICKET AS t,LATERAL FLATTEN(INPUT => t.classification:categories,OUTER => TRUE) AS c WHERE t.status <> 'closed'),ticket_rollup AS(SELECT customer_id,tenant_id,COUNT(*) AS open_ticket_count,MAX(created_at) AS latest_ticket_at,ARRAY_AGG(OBJECT_CONSTRUCT_KEEP_NULL( 'ticket_id',ticket_id, 'severity',severity, 'subject',subject, 'category',category, 'confidence',category_confidence)) WITHIN GROUP(ORDER BY created_at DESC,ticket_id) AS tickets FROM open_tickets GROUP BY customer_id,tenant_id) SELECT p.tenant_id,p.region,p.customer_id,p.email,p.display_name,COALESCE(r.open_ticket_count,0) AS open_ticket_count,r.latest_ticket_at,COALESCE(r.tickets,ARRAY_CONSTRUCT()) AS tickets,OBJECT_CONSTRUCT_KEEP_NULL( 'locale',p.profile:locale::STRING, 'vip',p.profile:flags:vip::BOOLEAN, 'last_login_at',p.profile:activity:last_login_at::STRING) AS profile_summary FROM latest_profile AS p LEFT JOIN ticket_rollup AS r ON p.customer_id = r.customer_id AND p.tenant_id = r.tenant_id;
